using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ──────────────────────────────────────────────
    // CalculateTotal – DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(25.00, 2, 0.10, 55.00, DisplayName = "Two items, 10% tax")]
    [DataRow(99.99, 3, 0.08, 323.97, DisplayName = "Three items, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price, any quantity")]
    [DataRow(15.50, 0, 0.15, 0.00, DisplayName = "Zero quantity returns zero")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "100% tax doubles the price")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        // Arrange – DataRow doesn't support decimal literals, so cast from double
        var price = (decimal)unitPrice;
        var tax = (decimal)taxRate;
        var expectedTotal = (decimal)expected;

        // Act
        var result = _calculator.CalculateTotal(price, quantity, tax);

        // Assert
        Assert.AreEqual(expectedTotal, Math.Round(result, 2));
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative price throws")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity throws")]
    [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Negative tax rate throws")]
    [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax rate > 1 throws")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    // ──────────────────────────────────────────────
    // ApplyDiscount – DynamicData tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountValidCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        // Act
        var result = _calculator.ApplyDiscount(price, discountPercent);

        // Assert
        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    private static IEnumerable<object[]> ApplyDiscountValidCases()
    {
        yield return [200.00m, 0m, 200.00m, "No discount"];
        yield return [200.00m, 10m, 180.00m, "10% off"];
        yield return [200.00m, 25m, 150.00m, "25% off"];
        yield return [200.00m, 50m, 100.00m, "50% off"];
        yield return [200.00m, 100m, 0.00m, "100% off (free)"];
        yield return [0.00m, 50m, 0.00m, "Zero price with discount"];
        yield return [49.99m, 15m, 42.4915m, "Fractional result"];
    }

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountInvalidCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRangeException(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    private static IEnumerable<object[]> ApplyDiscountInvalidCases()
    {
        yield return [100.00m, -1m];
        yield return [100.00m, 100.01m];
        yield return [100.00m, 200m];
    }

    // ──────────────────────────────────────────────
    // FormatPrice – DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default USD symbol")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "£", "£0.00", DisplayName = "Zero with GBP")]
    [DataRow(9.9, "$", "$9.90", DisplayName = "Pads to two decimals")]
    public void FormatPrice_WithValidInputs_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

